#!/usr/bin/env python3
"""Standalone Google Colab T4 runner for corrected ShapeNetPart training.

Paste this entire file into one Colab code cell and run it, or upload the file
and execute it. It installs dependencies, mounts Google Drive, prepares the
normal-enabled ShapeNetPart train/val/test splits, resumes when possible, and
starts training.
"""

from __future__ import annotations

import base64
import io
import os
import shutil
import subprocess
import sys
import tarfile
import time
import zipfile
from pathlib import Path


# User settings. These defaults are conservative for a Colab T4 (16 GB).
MOUNT_GOOGLE_DRIVE = True
AUTO_RESUME = True
USE_NORMALS_DATASET = True
EPOCHS = 250
BATCH_SIZE = 24
NUM_WORKERS = 2
CHECKPOINT_INTERVAL = 5
DRIVE_PROJECT_DIR = "/content/drive/MyDrive/ASP_SNN_ShapeNetPart_v2"
RUNTIME_DIR = Path("/content/asp_snn_shapenetpart")
LOCAL_DATA_ROOT = Path("/content/asp_snn_data")
RAW_NORMAL_URL = (
    "https://shapenet.cs.stanford.edu/media/"
    "shapenetcore_partanno_segmentation_benchmark_v0_normal.zip"
)
NORMAL_GDRIVE_ID = "1W3SEE-dY1sxvlECcOwWSDYemwHEUbJIS"
HDF5_GDRIVE_ID = "1tEnSGAdgfp-NPVS5y_ALD8eF18bzwhM_"
CACHE_VERSION = "normals_split_93a12a7cbce7"
BUNDLE_SHA256 = "93a12a7cbce70625029aed87a526ca5c82187c0632f862d6fda1bf3a5375da0e"
BUNDLE_B64 = """"""


def run(command, cwd=None):
    print("+", " ".join(map(str, command)), flush=True)
    subprocess.run(
        [str(item) for item in command],
        cwd=str(cwd) if cwd else None,
        check=True,
    )


def install_dependencies():
    packages = ["pyyaml", "h5py", "gdown", "requests"]
    run([sys.executable, "-m", "pip", "install", "-q", *packages])


def mount_drive():
    if not MOUNT_GOOGLE_DRIVE:
        return None
    try:
        from google.colab import drive

        drive.mount("/content/drive")
        path = Path(DRIVE_PROJECT_DIR)
        path.mkdir(parents=True, exist_ok=True)
        return path
    except Exception as exc:
        print(f"Google Drive mount failed; using local storage: {exc}")
        return None


def extract_project():
    payload = base64.b64decode(BUNDLE_B64.encode("ascii"))
    digest = __import__("hashlib").sha256(payload).hexdigest()
    if digest != BUNDLE_SHA256:
        raise RuntimeError("Embedded project payload failed its checksum")
    if RUNTIME_DIR.exists():
        shutil.rmtree(RUNTIME_DIR)
    RUNTIME_DIR.mkdir(parents=True)
    with tarfile.open(fileobj=io.BytesIO(payload), mode="r:gz") as archive:
        try:
            archive.extractall(RUNTIME_DIR, filter="data")
        except TypeError:
            archive.extractall(RUNTIME_DIR)
    print(f"Corrected project extracted to {RUNTIME_DIR}")


def download_file(url, destination):
    import requests

    destination.parent.mkdir(parents=True, exist_ok=True)
    partial = destination.with_suffix(destination.suffix + ".part")
    headers = {"User-Agent": "Mozilla/5.0 Colab ShapeNetPart runner"}
    with requests.get(
        url, stream=True, timeout=(30, 180), headers=headers
    ) as response:
        response.raise_for_status()
        total = int(response.headers.get("content-length", 0))
        written = 0
        last_report = 0.0
        with partial.open("wb") as handle:
            for chunk in response.iter_content(chunk_size=1024 * 1024):
                if not chunk:
                    continue
                handle.write(chunk)
                written += len(chunk)
                now = time.time()
                if now - last_report >= 5:
                    if total:
                        print(
                            f"Downloaded {written / 1e6:.0f}/"
                            f"{total / 1e6:.0f} MB",
                            flush=True,
                        )
                    else:
                        print(f"Downloaded {written / 1e6:.0f} MB", flush=True)
                    last_report = now
    partial.replace(destination)


def valid_dataset(data_dir):
    return (
        data_dir.exists()
        and any(data_dir.glob("train*.h5"))
        and any(data_dir.glob("test*.h5"))
    )


def restore_dataset_cache(cache_path, data_dir):
    if not cache_path.exists():
        return False
    print(f"Restoring prepared dataset cache from {cache_path}")
    if data_dir.exists():
        shutil.rmtree(data_dir)
    data_dir.parent.mkdir(parents=True, exist_ok=True)
    with tarfile.open(cache_path, "r:gz") as archive:
        try:
            archive.extractall(data_dir.parent, filter="data")
        except TypeError:
            archive.extractall(data_dir.parent)
    return valid_dataset(data_dir)


def save_dataset_cache(cache_path, data_dir):
    if cache_path.parent.exists():
        print(f"Saving prepared dataset cache to {cache_path}")
        temporary = cache_path.with_suffix(".tmp")
        with tarfile.open(temporary, "w:gz") as archive:
            archive.add(data_dir, arcname=data_dir.name)
        temporary.replace(cache_path)


def prepare_normals_dataset(data_dir):
    archive_path = LOCAL_DATA_ROOT / "shapenetpart_normal.tar"
    zip_fallback = LOCAL_DATA_ROOT / "shapenetpart_normal.zip"
    raw_extract = LOCAL_DATA_ROOT / "raw_normal"
    MIN_ARCHIVE_BYTES = 100_000_000  # raw normal zip is ~600 MB
    if (
        not archive_path.exists()
        or archive_path.stat().st_size < MIN_ARCHIVE_BYTES
    ):
        archive_path.unlink(missing_ok=True)
        print("Downloading PointNeXt normal-enabled ShapeNetPart mirror...")
        try:
            import gdown

            result = gdown.download(
                id=NORMAL_GDRIVE_ID,
                output=str(archive_path),
                quiet=False,
            )
            if (
                not result
                or archive_path.stat().st_size < MIN_ARCHIVE_BYTES
            ):
                raise RuntimeError("Google Drive returned an incomplete archive")
        except Exception as exc:
            archive_path.unlink(missing_ok=True)
            print(f"PointNeXt mirror failed; trying Stanford: {exc}")
            download_file(RAW_NORMAL_URL, zip_fallback)
            archive_path = zip_fallback
    if raw_extract.exists():
        shutil.rmtree(raw_extract)
    raw_extract.mkdir(parents=True)
    print("Extracting raw ShapeNetPart archive...")
    if zipfile.is_zipfile(archive_path):
        with zipfile.ZipFile(archive_path) as archive:
            archive.extractall(raw_extract)
    else:
        with tarfile.open(archive_path, "r:*") as archive:
            try:
                archive.extractall(raw_extract, filter="data")
            except TypeError:
                archive.extractall(raw_extract)
    split_files = list(
        raw_extract.rglob(
            "train_test_split/shuffled_train_file_list.json"
        )
    )
    if not split_files:
        raise RuntimeError("Raw archive does not contain ShapeNetPart splits")
    raw_dir = split_files[0].parent.parent
    run(
        [
            sys.executable,
            "datasets/convert_shapenet_raw.py",
            "--raw_dir",
            raw_dir,
            "--out_dir",
            data_dir,
        ],
        cwd=RUNTIME_DIR,
    )


def prepare_hdf5_mirror(data_dir):
    import gdown

    archive_path = LOCAL_DATA_ROOT / "shapenetpart_hdf5.zip"
    extract_dir = LOCAL_DATA_ROOT / "hdf5_mirror"
    MIN_HDF5_BYTES = 100_000_000  # packed HDF5 zip is ~350-400 MB
    if (
        not archive_path.exists()
        or archive_path.stat().st_size < MIN_HDF5_BYTES
    ):
        archive_path.unlink(missing_ok=True)
        print("Downloading prepared ShapeNetPart HDF5 mirror...")
        result = gdown.download(
            id=HDF5_GDRIVE_ID,
            output=str(archive_path),
            quiet=False,
        )
        if (
            not result
            or archive_path.stat().st_size < MIN_HDF5_BYTES
        ):
            raise RuntimeError("Prepared HDF5 mirror download was incomplete")
    if extract_dir.exists():
        shutil.rmtree(extract_dir)
    extract_dir.mkdir(parents=True)
    with zipfile.ZipFile(archive_path) as archive:
        archive.extractall(extract_dir)
    candidates = []
    for train_file in extract_dir.rglob("train*.h5"):
        parent = train_file.parent
        if any(parent.glob("test*.h5")):
            candidates.append(parent)
    if not candidates:
        raise RuntimeError("Prepared mirror contains no train/test HDF5 folder")
    source = candidates[0]
    if data_dir.exists():
        shutil.rmtree(data_dir)
    shutil.copytree(source, data_dir)


def prepare_dataset(persistent_dir):
    data_dir = LOCAL_DATA_ROOT / "shapenet_part_seg_hdf5_data"
    cache_path = (
        persistent_dir / "cache" / f"shapenetpart_{CACHE_VERSION}.tar.gz"
        if persistent_dir
        else Path("/nonexistent")
    )
    if persistent_dir:
        cache_path.parent.mkdir(parents=True, exist_ok=True)
    if restore_dataset_cache(cache_path, data_dir):
        return data_dir

    if data_dir.exists():
        shutil.rmtree(data_dir)
    LOCAL_DATA_ROOT.mkdir(parents=True, exist_ok=True)
    try:
        if not USE_NORMALS_DATASET:
            raise RuntimeError("normal-enabled conversion disabled")
        prepare_normals_dataset(data_dir)
    except Exception as exc:
        print(
            "Normal-enabled dataset preparation failed; falling back to the "
            f"prepared xyz HDF5 mirror: {exc}"
        )
        try:
            prepare_hdf5_mirror(data_dir)
        except Exception as mirror_exc:
            print(
                "Prepared mirror failed; making one final download attempt "
                f"through the bundled downloader: {mirror_exc}"
            )
            try:
                run(
                    [sys.executable, "datasets/download.py", "--shapenet"],
                    cwd=RUNTIME_DIR,
                )
                fallback = (
                    RUNTIME_DIR / "data" / "shapenet_part_seg_hdf5_data"
                )
                if data_dir.exists():
                    shutil.rmtree(data_dir)
                shutil.copytree(fallback, data_dir)
            except Exception as dl_exc:
                print(f"Bundled downloader also failed: {dl_exc}")

    if not valid_dataset(data_dir):
        raise RuntimeError("ShapeNetPart preparation produced no usable data")
    if persistent_dir:
        save_dataset_cache(cache_path, data_dir)
    return data_dir


def write_colab_config(data_dir, output_dir):
    import yaml

    source = RUNTIME_DIR / "configs" / "shapenet_seg.yaml"
    config = yaml.safe_load(source.read_text(encoding="utf-8"))
    config.update(
        {
            "data_dir": str(data_dir),
            "epochs": EPOCHS,
            "batch_size": BATCH_SIZE,
            "num_workers": NUM_WORKERS,
            "use_amp": True,
            "checkpoint_interval": CHECKPOINT_INTERVAL,
            "ckpt_dir": str(output_dir / "checkpoints"),
            "log_dir": str(output_dir / "logs"),
        }
    )
    output_dir.mkdir(parents=True, exist_ok=True)
    (output_dir / "checkpoints").mkdir(exist_ok=True)
    (output_dir / "logs").mkdir(exist_ok=True)
    config_path = output_dir / "shapenet_colab_t4.yaml"
    config_path.write_text(
        yaml.safe_dump(config, sort_keys=False), encoding="utf-8"
    )
    return config_path


def package_results(output_dir):
    result_zip = output_dir / "shapenetpart_colab_results.zip"
    temporary = result_zip.with_suffix(".tmp")
    with zipfile.ZipFile(
        temporary, "w", compression=zipfile.ZIP_DEFLATED
    ) as archive:
        for folder in ("checkpoints", "logs"):
            root = output_dir / folder
            if root.exists():
                for path in root.rglob("*"):
                    if path.is_file():
                        archive.write(path, path.relative_to(output_dir))
        config = output_dir / "shapenet_colab_t4.yaml"
        if config.exists():
            archive.write(config, config.name)
    temporary.replace(result_zip)
    print(f"Downloadable results: {result_zip}")


def main():
    install_dependencies()
    import torch

    if not torch.cuda.is_available():
        raise SystemExit(
            "No CUDA GPU detected. In Colab select Runtime > Change runtime "
            "type > T4 GPU, then run this cell again."
        )
    gpu = torch.cuda.get_device_properties(0)
    print(
        f"GPU: {gpu.name}, VRAM: {gpu.total_memory / 1024 ** 3:.1f} GiB"
    )

    persistent_dir = mount_drive()
    output_dir = persistent_dir or Path("/content/ASP_SNN_ShapeNetPart_v2")
    extract_project()
    data_dir = prepare_dataset(persistent_dir)
    config_path = write_colab_config(data_dir, output_dir)

    command = [
        sys.executable,
        "train_shapenet.py",
        "--config",
        config_path,
    ]
    last_checkpoint = output_dir / "checkpoints" / "shapenet_last.pt"
    if AUTO_RESUME and last_checkpoint.exists():
        command.extend(["--resume", last_checkpoint])
        print(f"Auto-resuming from {last_checkpoint}")

    print(
        f"Starting ShapeNetPart training: epochs={EPOCHS}, "
        f"batch={BATCH_SIZE}, workers={NUM_WORKERS}"
    )
    try:
        run(command, cwd=RUNTIME_DIR)
    finally:
        package_results(output_dir)


if __name__ == "__main__":
    main()
